const hamburger=document.querySelector(".hamburger"),navMenu=document.querySelector(".nav-menu");hamburger.addEventListener("click",()=>{navMenu.classList.toggle("active")}),document.querySelectorAll(".nav-link").forEach(e=>e.addEventListener("click",()=>{navMenu.classList.remove("active")})),document.querySelectorAll('a[href^="#"]').forEach(e=>{e.addEventListener("click",function(e){e.preventDefault();document.querySelector(this.getAttribute("href")).scrollIntoView({behavior:"smooth",block:"start"})})}),window.addEventListener("scroll",()=>{const e=document.querySelector(".navbar");window.scrollY>100?(e.style.background="rgba(10, 10, 10, 0.98)",e.style.borderBottom="1px solid rgba(220, 38, 38, 0.5)"):(e.style.background="rgba(10, 10, 10, 0.95)",e.style.borderBottom="1px solid rgba(220, 38, 38, 0.3)")});